import{_ as o,o as a,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"122. Hours Of Work","description":"","frontmatter":{"title":"122. Hours Of Work","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/122-hours-of-work.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/122-hours-of-work.md"}'),t={name:"ebas/mental-health/health-professionals/hours-of-work/122-hours-of-work.md"};function n(i,e,h,l,d,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_122-hours-of-work" tabindex="-1">122. Hours Of Work <a class="header-anchor" href="#_122-hours-of-work" aria-label="Permalink to &quot;122. Hours Of Work&quot;">​</a></h1><p><strong>122.1</strong> The hours for an ordinary week’s work shall be 38, or an average of 38 per week in a two- or four-week period, or by mutual agreement in a five week period in the case of an Employee working ten-hour shifts, and shall be worked either:</p><p><strong>(a)</strong> subject to practicability, in 152 hours per four-week period, to be worked as nineteen shifts each of eight hours; or</p><p><strong>(b)</strong> by mutual agreement:</p><p><strong>(i)</strong> in four days in shifts of not more than ten hours each; or</p><p><strong>(ii)</strong> otherwise, provided that the length of any ordinary shift shall not exceed ten hours.</p><p><strong>122.2</strong> Subject to the roster provisions, 80 hours may be worked in any two consecutive weeks, but not more than 50 ordinary hours may be worked in any one such week.</p><p><strong>122.3</strong> For all purposes the hourly rate is deemed to be the weekly rate prescribed by <a href="/eba/ebas/mental-health/health-professionals/classification-staffing/143-classifications-and-wages.html">clause 143</a> (Classification and Wages) divided by 38, provided that where the averaging system is used by full-time Employees, an Employee’s ordinary wage for ordinary hours is deemed to be the weekly rate prescribed in <a href="/eba/ebas/mental-health/health-professionals/classification-staffing/143-classifications-and-wages.html">clause 143</a> (Classification and Wages), and shall be paid each week even though more or less than 38 ordinary hours are worked in that week. NOTE: An Employee shall accrue a credit for each day in which they work ordinary hours in excess of the daily average of seven hours 36 minutes. The credit is carried forward so that in each cycle an accrued day off is paid.</p><p><strong>122.4</strong> All paid leave accrues the credit provided for by clause 122.3 above.</p><p><strong>122.5</strong> A paid leave day shall be identical to a worked day.</p><p><strong>122.6</strong> The deduction from leave credits shall be the same as the actual ordinary hours which would have been worked on that day.</p><p><strong>122.7</strong> An Employee who is absent from ordinary duty on unpaid leave shall accrue the appropriate credit without pay for the accrued day off.</p>',12)])])}const u=o(t,[["render",n]]);export{p as __pageData,u as default};
